#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y, Z;
        scanf("%d %d %d", &X, &Y, &Z);
        int total = X * Y;
        if (total <= Z) {
            printf("0\n");
        } else {
            int excess = total - Z;
            int ans = (excess + Y - 1) / Y; // ceil division
            printf("%d\n", ans);
        }
    }
    return 0;
}

