#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        X = int(next(it))
        Y = int(next(it))
        Z = int(next(it))
        total = X * Y
        if total <= Z:
            out_lines.append('0')
        else:
            excess = total - Z
            ans = (excess + Y - 1) // Y
            out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

